import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';

export default function Navbar() {
  const { usuario, cerrarSesion, esAdmin } = useAuth();
  const { darkMode, toggleDark } = useTheme();
  const navigate = useNavigate();
  const location = useLocation();

  const handleSalir = () => { cerrarSesion(); navigate('/'); };

  const isActive = (path) => location.pathname === path;

  const linkStyle = (path) => ({
    padding: '6px 14px',
    borderRadius: 20,
    fontSize: 14,
    fontWeight: isActive(path) ? 600 : 400,
    color: isActive(path) ? 'white' : 'rgba(255,255,255,0.8)',
    background: isActive(path) ? 'rgba(255,255,255,0.2)' : 'transparent',
    textDecoration: 'none',
    transition: 'all 0.2s',
  });

  return (
    <nav style={{
      background: 'linear-gradient(135deg, #1e3a8a, #1e40af)',
      padding: '0 24px',
      height: 64,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
      position: 'sticky',
      top: 0,
      zIndex: 100,
    }}>

      {/* Logo */}
      <Link to="/" style={{ display: 'flex', alignItems: 'center', gap: 10, textDecoration: 'none' }}>
        <img src="/Logo-RedNorte.png" alt="RedNorte" style={{ height: 36, width: 'auto' }} />
        <div>
          <div style={{ color: 'white', fontWeight: 700, fontSize: 18, lineHeight: 1.1 }}>
            Red<span style={{ color: '#5eead4' }}>Norte</span>
          </div>
          <div style={{ color: 'rgba(255,255,255,0.6)', fontSize: 10, letterSpacing: '0.5px' }}>
            GESTIÓN DE SALUD
          </div>
        </div>
      </Link>

      {/* Links */}
      {usuario && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          {esAdmin ? (
            <>
              <Link to="/inicio" style={linkStyle('/inicio')}>Inicio</Link>
              <Link to="/admin/dashboard" style={linkStyle('/admin/dashboard')}>Dashboard</Link>
              <Link to="/admin/consultas" style={linkStyle('/admin/consultas')}>Consultas</Link>
              <Link to="/admin/usuarios" style={linkStyle('/admin/usuarios')}>Usuarios</Link>
              <Link to="/admin/reasignacion" style={linkStyle('/admin/reasignacion')}>Reasignación</Link>
            </>
          ) : (
            <>
              <Link to="/inicio" style={linkStyle('/inicio')}>Inicio</Link>
              <Link to="/mis-consultas" style={linkStyle('/mis-consultas')}>Mis Consultas</Link>
              <Link to="/nueva-consulta" style={linkStyle('/nueva-consulta')}>Nueva Consulta</Link>
              <Link to="/perfil" style={linkStyle('/perfil')}>Mi Perfil</Link>
            </>
          )}
        </div>
      )}

      {/* Acciones */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
        <button onClick={toggleDark} style={{
          background: 'rgba(255,255,255,0.15)', border: 'none', borderRadius: '50%',
          width: 36, height: 36, cursor: 'pointer', fontSize: 16,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          {darkMode ? '☀️' : '🌙'}
        </button>
        {usuario ? (
          <button onClick={handleSalir} style={{
            background: 'rgba(255,255,255,0.15)', border: '1px solid rgba(255,255,255,0.3)',
            borderRadius: 20, padding: '6px 18px', color: 'white', cursor: 'pointer', fontSize: 14, fontWeight: 500,
          }}>Salir</button>
        ) : (
          <Link to="/login" style={{
            background: 'white', borderRadius: 20, padding: '6px 18px',
            color: '#1e40af', fontWeight: 600, fontSize: 14, textDecoration: 'none',
          }}>Ingresar</Link>
        )}
      </div>
    </nav>
  );
}
